-- 固定ページ（ホーム・概要・アクセス）
INSERT INTO site_pages (slug, title, content, metadata) VALUES
  ('home', 'ホーム', '星ヶ丘こどもクラブは、保護者の手で運営する学童保育施設です。約30名の児童が、宿題・遊び・おやつの時間を通じて、のびのびと放課後を過ごしています。', '{"subtitle":"星ヶ丘こどもクラブは、保護者の手で運営する学童保育施設です。","features_heading":"星ヶ丘こどもクラブの特徴","features_subtitle":"子どもたちの「やりたい」を大切に、あたたかい放課後の居場所を提供します。","features":[{"icon":"Users","title":"父母運営のあたたかさ","description":"保護者が運営に参加することで、家庭とクラブが一体となってお子さまの成長を見守ります。"},{"icon":"Heart","title":"異年齢の交流","description":"1年生から6年生まで一緒に過ごすことで、思いやりやリーダーシップが自然と育まれます。"},{"icon":"Calendar","title":"季節の行事","description":"お花見、七夕、クリスマス会など四季折々の行事を通じて、豊かな思い出を育みます。"},{"icon":"Apple","title":"食育・おやつ","description":"栄養バランスを考えたおやつで、旬の味覚を楽しみます。みんなで食べる時間も大切にしています。"}]}'::jsonb),
  ('about', '学童について', '当学童保育では、放課後の子どもたちが安心して過ごせる環境を提供しています。', '{"subtitle":"子どもたちが「ただいま！」と駆け込んでくる、あたたかい居場所です。","vision_heading":"私たちの想い","vision_emoji":"🏠","vision_tagline":"家庭のようなあたたかさ","schedule":[{"time":"14:00","label":"入室・宿題タイム","emoji":"📝"},{"time":"15:30","label":"おやつ","emoji":"🍪"},{"time":"16:00","label":"自由遊び・活動","emoji":"⚽"},{"time":"18:00","label":"お迎え・退室","emoji":"👋"}],"facility_info":[{"label":"施設名","value":"星ヶ丘こどもクラブ"},{"label":"所在地","value":"名古屋市千種区星が丘1-5 アーバンラフレ集会所内"},{"label":"運営形態","value":"父母運営型 学童保育"},{"label":"対象","value":"小学1〜6年生"},{"label":"定員","value":"約30名"},{"label":"開所時間","value":"平日 放課後〜19:00 / 土曜・長期休暇 8:00〜19:00"},{"label":"休所日","value":"日曜・祝日・年末年始"},{"label":"TEL","value":"052-783-1447"},{"label":"専任指導員","value":"加悦（かや）"}]}'::jsonb),
  ('access', 'アクセス', '〒464-0021 名古屋市千種区星が丘1-5 アーバンラフレ集会所内　最寄り駅：地下鉄東山線 星ヶ丘駅 徒歩8分', '{"subtitle":"お気軽にお越しください。見学も随時受け付けております。","phone":"052-783-1447","phone_hours":"受付: 平日 14:00〜19:00","opening_hours":"平日: 放課後〜19:00\n土曜・長期休暇: 8:00〜19:00","visit_heading":"見学のお申し込み","visit_text":"入所をご検討中の方は、お気軽にお問い合わせください。\n施設の見学は随時受け付けております。\n\n携帯: 090-3832-0341\n専任指導員: 加悦（かや）"}'::jsonb),
  ('faq', 'Q&A', 'よくお寄せいただくご質問をまとめました。', '{"subtitle":"はじめての方もご安心ください。","questions":[{"q":"学童保育は何年生まで利用できますか？","a":"小学1年生から6年生までご利用いただけます。"},{"q":"見学はできますか？","a":"はい、随時受け付けております。お問い合わせフォームまたはお電話でお申し込みください。"},{"q":"保育時間は何時までですか？","a":"平日は放課後から19:00まで、土曜・長期休暇は8:00から19:00までです。延長保育もご相談ください。"},{"q":"おやつは出ますか？","a":"はい、毎日おやつの時間があります。アレルギー対応もしておりますので、入所時にご相談ください。"},{"q":"父母運営とはどういうことですか？","a":"保護者が運営主体となり、指導員と協力して学童保育を運営する形態です。保護者会で方針を決め、当番制で運営に参加いただきます。"},{"q":"長期休暇（夏休みなど）も利用できますか？","a":"はい、夏休み・冬休み・春休みも8:00から19:00まで開所しています。"},{"q":"入所の申し込みはいつからできますか？","a":"例年、翌年度の募集を秋頃に開始します。年度途中の入所もご相談ください。"},{"q":"送迎はありますか？","a":"基本的にお子さんは学校から直接来所し、お迎えは保護者の方にお願いしております。"}]}'::jsonb),
  ('daily-life', '日々の生活', '放課後の時間を活用し、子どもたちが「自分らしく」いられる居場所を提供します。異年齢の交流を通じて、社会性、自立心、そして豊かな感性を育みます。', '{"subtitle":"のびのび、すくすく。放課後の「もうひとつの家」","activities":[{"emoji":"⚽","title":"自由遊び","description":"外遊びや室内での創作活動など、子どもたちの「やりたい」を尊重します。異年齢の子どもたちが一緒に遊ぶことで、自然と社会性が身につきます。"},{"emoji":"📝","title":"学習サポート","description":"宿題だけでなく、自ら学ぶ姿勢を育むための静かな環境を整えています。わからないところは指導員がサポートします。"},{"emoji":"🍪","title":"おやつの時間","description":"栄養バランスを考えたおやつを提供。食育の一環として旬の味覚も楽しみます。みんなで食べるおやつは格別です。"},{"emoji":"🎨","title":"創作活動","description":"工作、お絵かき、手芸など、子どもたちの創造力を伸ばす活動を行っています。"},{"emoji":"📚","title":"読書タイム","description":"絵本や児童書を豊富に揃えています。静かに本の世界に浸る時間も大切にしています。"},{"emoji":"🌱","title":"自然体験","description":"近隣の公園での虫取りや植物観察など、四季を感じる活動を通して豊かな感性を育みます。"}],"events":[{"emoji":"🌸","title":"お花見遠足","season":"春"},{"emoji":"🎋","title":"七夕まつり","season":"夏"},{"emoji":"🏊","title":"プール・水遊び","season":"夏"},{"emoji":"🍠","title":"芋掘り遠足","season":"秋"},{"emoji":"🎃","title":"ハロウィン","season":"秋"},{"emoji":"🎄","title":"クリスマス会","season":"冬"},{"emoji":"🎍","title":"お正月遊び","season":"冬"},{"emoji":"🎂","title":"お誕生日会","season":"通年"}],"philosophy_heading":"親と子の「共育ち」","philosophy_emoji":"🤝","philosophy_text":"「1人の子どもは、みんなの子ども。1人の親は、みんなの親。」を合言葉に、家庭とクラブが協力してお子さまの成長を見守ります。\n\n大人も子どもも共に育ち合う環境を目指し、保護者同士の交流も大切にしています。"}'::jsonb)
ON CONFLICT (slug) DO NOTHING;

